92	export default function PhaseDetail({ phase, spec, prd, onSave, onCancel }: PhaseDetailProps) {
93	  const [draft, setDraft] = useState<Phase>({ ...phase });
94	  const [dirty, setDirty] = useState(false);
95	
96	  useEffect(() => {
97	    setDraft({ ...phase });
98	    setDirty(false);
99	  }, [phase.id]);
100	
101	  function update<K extends keyof Phase>(key: K, value: Phase[K]) {
102	    setDraft((prev) => ({ ...prev, [key]: value }));
103	    setDirty(true);
104	  }
105	
106	  function handleSave() {
107	    onSave({ ...draft, updatedAt: new Date().toISOString() });
108	    setDirty(false);
109	  }
110	
111	  return (
112	    <div style={{ fontFamily: "system-ui, sans-serif", padding: "16px" }}>
113	      {/* Editable fields */}
114	      <div style={FIELD_STYLE}>
115	        <label style={LABEL_STYLE}>Phase Number</label>
116	        <input
117	          type="number"
118	          min={1}
119	          value={draft.phaseNumber}
120	          onChange={(e) => update("phaseNumber", Number(e.target.value))}
121	          style={{ ...INPUT_STYLE, width: "80px" }}
122	        />
123	      </div>
124	
125	      <div style={FIELD_STYLE}>
126	        <label style={LABEL_STYLE}>Title</label>
127	        <input
128	          type="text"
129	          value={draft.title}
130	          onChange={(e) => update("title", e.target.value)}
131	          placeholder="Phase title"
132	          style={INPUT_STYLE}
133	        />
134	      </div>
135	
136	      <div style={FIELD_STYLE}>
137	        <label style={LABEL_STYLE}>Objective</label>
138	        <input
139	          type="text"
140	          value={draft.objective}
141	          onChange={(e) => update("objective", e.target.value)}
142	          placeholder="What this phase achieves"
143	          style={INPUT_STYLE}
144	        />
145	      </div>
146	
147	      <div style={FIELD_STYLE}>
148	        <label style={LABEL_STYLE}>Description</label>
149	        <textarea
150	          value={draft.description}
151	          onChange={(e) => update("description", e.target.value)}
152	          placeholder="Detailed description of the phase scope and approach"
153	          style={TEXTAREA_STYLE}
154	        />
155	      </div>
156	
157	      <div style={{ display: "flex", gap: "12px", marginBottom: "14px" }}>
158	        <div style={{ flex: 1 }}>
159	          <label style={LABEL_STYLE}>Status</label>
160	          <select
161	            value={draft.status}
162	            onChange={(e) => update("status", e.target.value as PhaseStatus)}
163	            style={SELECT_STYLE}
164	          >
165	            {PHASE_STATUS_OPTIONS.map((opt) => (
166	              <option key={opt.value} value={opt.value}>{opt.label}</option>
167	            ))}
168	          </select>
169	        </div>
170	        <div style={{ flex: 1 }}>
171	          <label style={LABEL_STYLE}>Freeze State</label>
172	          <select
173	            value={draft.freezeState}
174	            onChange={(e) => update("freezeState", e.target.value as FreezeState)}
175	            style={SELECT_STYLE}
176	          >
177	            {FREEZE_STATE_OPTIONS.map((opt) => (
178	              <option key={opt.value} value={opt.value}>{opt.label}</option>
179	            ))}
180	          </select>
181	        </div>
182	      </div>
183	
184	      <div style={FIELD_STYLE}>
185	        <label style={LABEL_STYLE}>Prerequisites</label>
186	        <textarea
187	          value={draft.prerequisites}
188	          onChange={(e) => update("prerequisites", e.target.value)}
189	          placeholder="What must be true or complete before this phase starts"
190	          style={TEXTAREA_STYLE}
191	        />
192	      </div>
193	
194	      <div style={FIELD_STYLE}>
195	        <label style={LABEL_STYLE}>Success Criteria</label>
196	        <textarea
197	          value={draft.successCriteria}
198	          onChange={(e) => update("successCriteria", e.target.value)}
199	          placeholder="How we know this phase is done"
200	          style={TEXTAREA_STYLE}
201	        />
202	      </div>
203	
204	      <div style={FIELD_STYLE}>
205	        <label style={LABEL_STYLE}>Risk Notes</label>
206	        <textarea
207	          value={draft.riskNotes}
208	          onChange={(e) => update("riskNotes", e.target.value)}
209	          placeholder="Known risks, mitigations, or open questions"
210	          style={TEXTAREA_STYLE}
211	        />
212	      </div>
213	
214	      {/* Save / Cancel */}
215	      <div style={{ display: "flex", gap: "8px", marginTop: "4px" }}>
216	        <button
217	          onClick={handleSave}
218	          disabled={!dirty}
219	          style={{
220	            padding: "7px 18px",
221	            backgroundColor: dirty ? "#2563eb" : "#93c5fd",
222	            color: "#fff",
223	            border: "none",
224	            borderRadius: "6px",
225	            cursor: dirty ? "pointer" : "default",
226	            fontSize: "13px",
227	            fontWeight: 500,
228	          }}
229	        >
230	          Save
231	        </button>
232	        <button
233	          onClick={onCancel}
234	          style={{
